<span class="line"><span style="color:#F9E2AF;font-style:italic;">                        Ok</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> ToolExecutionResult</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Success</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">output</span><span style="color:#9399B2;">),</span></span>
